INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L052$$, 2026, $$This effort is for procurement and installation of the Replacement Heads-Up Display (RHUD) onto the C-17 aircraft. Analysis indicates the current HUD, which is required to fly the C-17, is becoming
 unsupportable due to obsolescence. This effort retrofits the C-17 fleet with an RHUD that is certified as a Primary Flight Reference, providing improved reliability, maintainability, and supportability, while also
 providing growth to support future planned capability improvements. The total of 222 units will be sustainable for the planned life of the C-17 fleet. The RHUD retrofit started in FY21. Speedlines will commence
 in the future. To achieve the best unit cost for the USAF without extending the overall procurement timeline, remaining kits will be purchased with FY25 funds. FY26 funding is for installation of kits already
 purchased and other government costs.

 Projected allocations by component are subject to total force mission priorities and aircraft availability.

 Funding may be used to address Diminishing Manufacturing Sources (DMS) issues.

 This modification supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

 Milestone/Development Status

 The first RHUD was tested with RDT&E funding in FY 2018. The first production kitproof kits were purchased in FY 2019 and installed in FY 2021.$$, $$$$, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":52,"src_title":"C-17A","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 454, 454, $$47d40679d0870d93$$, $$2026-05-10T04:06:02.992954+00:00$$) ON CONFLICT DO NOTHING;
