INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L068$$, 2027, $$C-130H aircraft require Center Wing Box (CWB) replacement before reaching 38,000 equivalent flight hours (EFH) to avoid being placed on restricted operations. There are currently 113 C-130Hs and 10
 LC-130Hs in the Air Force inventory. This number will reduce to 52 C-130Hs and 10 LC-130Hs by 2029 after accounting for all C-130Js appropriated by Congress that have not yet delivered. Nine of these 52
 C-130Hs are projected to reach 38,000 EFHs between 2029-2036.

 The FY2027 funding procures two CWBs for installation in 2029. CWBs will be replaced with the Extended Service Life (ESL) CWB which has a service life of 98,000 EFHs. Installations are planned to be done at
 the Warner Robins Depot.

 Milestone/Development Status

