INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2032_L024$$, 2026, $$Lethal Miniature Aerial Missile System (LMAMS) is a single man-portable/operable, light-weight organic, beyond line-of-sight, precision guided, loitering aerial missile system capable of locating and engaging
 obscured and/or fleeting enemy targets who otherwise cannot be engaged by typical direct fire weapon systems. Front and Side Look High Resolution Electro-Optical (day) and Front Look Infrared (night)
 cameras allow the Warfighter to have eyes on the target for positive identification. LMAMS Wave-Off capability allows the operator to wave-off or re-direct the LMAMS flight path prior to impact, if necessary. The
 system is comprised of a fire control unit, launcher, missile, and a modular payload capable of high lethality against unprotected Combatant Personnel and producing casualties against Personnel in Soft Skinned
 Vehicles. LMAMS has the ability to be employed in less than two minutes.

 Justification:
 LMAMS has no FY 2027 funding.

 In accordance with Section 1815 of the FY08 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland defense
 missions, domestic emergency responses, and providing military support to civil authorities.$$, $$$$, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":94.2,"current_claimer_pid":"P_2032_L022","current_claimer_score":39.1,"margin":55.1,"src_li":19,"src_title":"LETHAL MINIATURE AERIAL MISSILE SYSTEM (LMAMS)","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Army/Missile Procurement Army.pdf$$, 238, 238, $$3988bf86fde60e2e$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L012$$, 2027, $$This Budget Line Item (BLI) was consolidated for the FY27 President's Budget (PB). The new BLI, 827000, improves transparency, execution, and long‑term planning.

 This vehicle group consists of armored loaders and dozers, water distribution trucks, and heavy construction equipment (dozers, large cranes, large dump trucks, rock crushers, motorized scrapers, well-drilling
 vehicles, compactors, wheel loaders, graders, cement mixers, paving machines, excavators, sewer trucks, refuse trucks, trenches and backhoes).

 The assets are critical to the Air Force mission and are crucial to keeping sortie generation/sortie sustainment missions supported and operational. The types of items contained in this category document are
 critical (deployed) assets used in direct support of Air Force units engaged in contingency operations.

 The FY 2026 spend plan amount for 3080 includes 28,711 thousand of discretionary and 14,000 thousand of mandatory (reconciliation) for a total of 42,711 thousand.

 FIAR Compliance Statement:
 - This requirement (or modification) supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.$$, $$$$, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":100,"current_claimer_pid":"P_3080_L011_v21","current_claimer_score":100.0,"margin":0.0,"src_li":11,"src_title":"Base Maintenance Support Vehicles","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Other Procurement.pdf$$, 65, 65, $$dcb034b875d0c6b6$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
