INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2031_L002$$, 2027, $$The MQ-1C Gray Eagle provides the Army with an Extended Range, Multi-Purpose (ERMP) Uncrewed Aircraft System (UAS) in Multi-Domain Operations (MDO); capable of executing reconnaissance, security,
 attack, and intelligence collection missions in Range of Military Operations (ROMO). Sensors/Payloads include an Electro-Optical/Infrared/Laser Designator (EO/IR/LD), Synthetic Aperture Radar/Moving Target
 Indicator (SAR/MTI), Signals Intelligence (SIGINT), and HELLFIRE missiles providing long range, deep sense/attack with standoff.

 The MQ-1C Gray Eagle system consists of Aircraft (Modernized Extended Range), Single/Multi-Band Satellite Communication (SATCOM) Air Data Terminals (SB/MB-SADTs), Ground Expeditionary Equipment
 (Control Stations), Universal Ground Data Terminals (UGDTs), Single/Multi-Band SATCOM Ground Data Terminals (SB/MB-SGDTs), and Ground Based Sense And Avoid (GBSAA). Payloads include Electro-
 Optical/Infrared Laser Range Finder/Laser Designator (EO/IR/LD HD), Synthetic Aperture Radar/Ground Moving Target Indicator (SAR/GMTI), and Communication Relay to provide an operational ready
 capability.

 4 May 2017, the Army approved an Army Acquisition Objective (AAO) adjustment to bring the total requirement to 204 MQ-1C Gray Eagle aircraft.

 Justification:
 There is no FY 2027 funding programmed for MQ-1 UAV.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                           Date: April 2026
