INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2031_L034$$, 2027, $$Utility Helicopter Mods include modifications to the UH-60 Black Hawk and the UH-72 Lakota helicopters. The UH-60 Black Hawk helicopter is the Army's utility helicopter for the near and midterm force. It is a
 twin engine, single rotor, four bladed utility helicopter used for air assault, general support, command & control, and aero-medical evacuations (MEDEVAC). The UH-60 is joint force capable, providing 24 hour/
 day support including operations at night and in adverse weather conditions. The UH-60 is designed to carry a crew of four plus eleven combat equipped troops or an external load up to 9,000 pounds. The
 UH-60 Black Hawk was fielded in 1978 as a replacement for the UH-1. From 1978 to 1988, UH-60As were produced. In 1989 production of UH-60Ls with improved engines and drive train began. In 2007, full
 rate production of UH-60Ms began which provided a digital cockpit, digital Flight Management System (FMS), improved engine, and wide-cord main rotor blades. The UH-72 Lakota helicopter provides general
 aviation support for aviation units in the active and reserve components.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                             Date: April 2026
