INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2031_L009$$, 2026, $$AH-64E Reman is a complete remanufacture using a new airframe and meets all the requirements for Army and Joint interoperability goals for the future and adds significant combat capability while addressing
 obsolescence issues, ensuring the aircraft remains a viable combat multiplier beyond its lifecycle. The Army's only heavy attack helicopter, the AH-64E is fully digital with the latest technologies, which adds
 significant combat capability to the aircraft. The AH-64E Apache is implementing an incremental design and fielding strategy as noted in the approved Capability Production Document (CPD). AH-64E Capability
 Version 1 includes Improved Drive and Propulsion System, Composite Main Rotor Blades (CMRB), Unmanned Aircraft System (UAS) Level III-IV Control, Improved Communications Suite, Improved Electronics /
 Modular Open Systems Approach, and Radar Electronics Unit (REU). Capability Version 4 includes Link 16, Air to Air to Ground (AAG) Video Relay, System Level Embedded Diagnostics (SLED), and provisions
 for Reduced-Size Crashworthy External Fuel Systems (RCEFS). Capability Version 6 includes Fire Control Radar (FCR) enhancements, Maritime Targeting Mode, Expanded Link-16, Image Blending, Multi-
 Mode Laser (MML), and Interactive Electronic Technical Manual (IETM) Upgrades. Production Lots 1-4 are Version 1 capable, Production Lots 5-8 are Version 4 capable, and Version 6 is included into the
 remaining Production Lots beginning with Production Lot 9. Upgrades are integrated as incremental block modifications. Other associated Government Furnished Equipment (GFE) such as the GEN2 Radar
 Frequency Interferometer (G2RFI), Radar Electronics Unit (REU), and Manned/Unmanned Teaming Extended Capability (MUMT-X) will be procured and provided in accordance with the basis of issue plan. The
 program addresses operational shortfalls identified during real-world combat missions, meets Apache Capability Production Document (CPD) requirements for modernization, and provides necessary training,
 initial spares, and Peculiar Ground Support Equipment (PGSE). AH-64E aircraft entered the fleet in 2012.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                             Date: April 2026
