INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2031_L013$$, 2026, $$The Utility Helicopter (UH)-60M Black Hawk Helicopter serves as the Army's utility helicopter for the near and midterm force and is in line with the Army's Modernization Strategy, the National Military Strategy,
 and the National Defense Strategy. The UH-60M Black Hawk is a digital networked platform with greater range and lift to support maneuver Commanders through air assault, general support command
 and control, and aeromedical evacuation. Full rate production for this new build helicopter began in 2007. The current UH-60 Army Acquisition Objective (AAO) is 1957 which will be obtained by continued
 procurement of UH-60M. The HH-60M is a version of the UH-60M that includes an integrated Medical Evacuation (MEDEVAC) Mission Equipment Package (MEP). The HH-60M provides the joint services
 with an aeromedical evacuation capability enabling the Critical Care Flight Paramedic (CCFP) to provide lifesaving, enroute medical treatment to casualties who have suffered survivable wounds. Aeromedical
 evacuation builds the morale of the warfighter while clearing the battlefield allowing the tactical commander to continue the mission.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                                              Date: April 2026
