INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3020_L019$$, 2027, $$AMRAAM (Advanced Medium Range Air-to-Air Missile) is a joint United States Air Force (USAF)/Department of Navy (DON), Acquisition Category 1C program with USAF as lead service. AMRAAM is the
 premier all-weather, all-environment radar guided missile with improved capabilities against very low and high-altitude targets in an electronic attack environment. The current AMRAAM AIM-120D3 variant
 delivers improved performance via Global Positioning System (GPS) aided navigation; two-way datalink capability for enhanced aircrew survivability and improved network compatibility; and incorporates new
 guidance software that improves kinematic performance and weapon effectiveness.

 The FY27 budget request includes Multiyear Procurement (MYP) in support of AMRAAM. This MYP strategy generates efficiencies that result in greater production capacity, accelerated delivery, and lower unit
 costs. The MYP contracting and financing strategy leverages savings generated through economic order quantities of material from sub-vendors, enabled by the establishment of steady and consistent total
 order quantities. Maintaining the total order quantities is critical to supporting the industrial base stability needed to achieve and sustain production capacity. Total order quantities of AMRAAM are funded across
 multiple budgets and customers including the U.S. Air Force, U.S. Navy, and FMS cases. Missile configurations may vary based on warfighter needs, which include assets used for training and Weapon System
 Evaluation Program (WSEP).

 Funding for this exhibit contained in PE 0207163F.$$, NULL, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":100,"current_claimer_pid":"P_3020_L018","current_claimer_score":100.0,"margin":0.0,"src_li":17,"src_title":"AMRAAM","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Aircraft  Missile Procurement.pdf$$, 131, 131, $$c30e82680b77606d$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3020_L019$$, 2026, $$In the FY 2024 budget request, the Department initiated a Multiyear Procurement (MYP) strategy for AMRAAM under the Large Lot Procurement (LLP) concept in which individual MYPs would be executed in
a concurrent and overlapping multiyear strategy so that synergies in production across different but related programs can generate efficiencies and result in greater production capacity, accelerated delivery,
and lower unit costs. LLP represents an evolution of the existing MYP contracting and financing strategy, that leverages the savings generated through the use of Economic Order Quantities (EOQ) financing to
procure additional lots of missiles under a Buy-to-Budget concept, to further improve efficiencies and yields.

For purposes of implementing FY25 full year CR funds, the MYP authority for AMRAAM has been removed.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":19,"src_title":"AMRAAM","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Missile Procurement.pdf$$, 163, 163, $$b7814738223b7fa9$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2031_L025$$, 2027, $$The MQ-1C Gray Eagle provides the Army with an Extended Range, Multi-Purpose (ERMP) Uncrewed Aircraft System (UAS) in Multi-Domain Operations (MDO); capable of executing reconnaissance, security,
 attack, and intelligence collection missions in Range of Military Operations (ROMO). Sensors/Payloads include an Electro-Optical/Infrared/Laser Designator (EO/IR/LD), Synthetic Aperture Radar/Moving Target
 Indicator (SAR/MTI), Signals Intelligence (SIGINT), and HELLFIRE missiles providing long range, deep sense/attack with standoff.

 The MQ-1C Gray Eagle Modification/Product Improvement Program (PIP) funding is required to address obsolescence while maintaining a MDO-ready capability. This effort involves the procurement of
 expeditionary ground equipment (control stations), datalinks (new single/multi-band satellite communication & line of sight terminals), avionics (increased processing power, M-Code navigators), payloads, and
 aircraft systems (Modernized Extended Range) in a Modular Open System Architecture (MOSA) supported by partitioned flight/mission software. Funding supports multi-phased integration efforts of hardware
 and software procurement in support of Army Assured-Positioning Navigation and Timing (A-PNT) requirements to allow the MQ-1C Gray Eagle to survive, persist, and operate effectively in GPS denied
 environments resulting in the fielding of M-Code navigators as required by Public Law 111-383. Procurement of new engine propulsion systems is necessary to maintain operational readiness for the enduring
 MQ-1C Gray Eagle fleet and provides the -25M Weapon Systems with a viable propulsion system.

